insert into sd_navi_comment values (1000001, 1000, 190801, 13, '我准备了各式各样的\\n小游戏哦！\\n要玩哪种小游戏？', 0, '2020-01-01 0:00:00', '2099-12-31 23:59:59');
insert into sd_navi_comment values (1000002, 1000, 190801, 13, '给你介绍有趣的小游戏！\\n你要玩哪种\\n小游戏呢？', 0, '2020-01-01 0:00:00', '2099-12-31 23:59:59');
insert into sd_navi_comment values (1001001, 1001, 190801, 13, '价格为{0}金币，\\n正在售卖中！\\n请一定要购入\\n游玩哦！', 0, '2020-01-01 0:00:00', '2099-12-31 23:59:59');
insert into sd_navi_comment values (1002001, 1002, 190801, 12, '点击活动的爱心！\\n帮助静流小姐和惠理子小姐\\n制作\\n巧克力蛋糕吧！', 0, '2020-01-01 0:00:00', '2099-12-31 23:59:59');
insert into sd_navi_comment values (1003001, 1003, 190801, 11, '拽着空花\\n飞向更远的地方吧！\\n用各种障碍让空花\\n心醉神迷！', 0, '2020-01-01 0:00:00', '2099-12-31 23:59:59');
insert into sd_navi_comment values (1004001, 1004, 190801, 3, '点击左右两边，击倒\\n奄美魔物吧！\\n看招！\\n琉球犬大回旋踢击！', 0, '2020-01-01 0:00:00', '2099-12-31 23:59:59');
insert into sd_navi_comment values (1005001, 1005, 190801, 7, '确定要点击屏幕\\n和龙族据点的各位一起\\n进行接龙对决吗？', 0, '2020-01-01 0:00:00', '2099-12-31 23:59:59');
